 61→function renderMetadataEntry(entry: ListItemMetadataEntry, index: number) {
 62→  switch (entry.type) {
 63→    case 'label':
 64→      return (
 65→        <DetailMetadata.Label
 66→          key={index}
 67→          title={entry.title}
 68→          text={entry.text}
 69→        />
 70→      );
 71→    case 'link':
 72→      return (
 73→        <DetailMetadata.Link
 74→          key={index}
 75→          title={entry.title}
 76→          text={entry.text}
 77→          target={entry.target}
 78→        />
 79→      );
 80→    case 'tag-list':
 81→      return (
 82→        <DetailMetadata.TagList key={index} title={entry.title}>
 83→          {entry.tags.map(tag => (
 84→            <DetailMetadata.Tag
 85→              key={tag.text}
 86→              text={tag.text}
 87→              color={tag.color}
 88→            />
 89→          ))}
 90→        </DetailMetadata.TagList>
 91→      );
 92→    case 'separator':
 93→      return <DetailMetadata.Separator key={index} />;
 94→  }
 95→}
