 1→import { useCallback, useRef, useState } from 'react';
 2→import type { AlertOptions } from '../components/alert/alert';
 3→
 4→export function useAlert() {
 5→  const [alertState, setAlertState] = useState<AlertOptions | null>(null);
 6→  const resolveRef = useRef<((confirmed: boolean) => void) | null>(null);
 7→
 8→  const confirmAlert = useCallback((
 9→    options: AlertOptions,
10→  ): Promise<boolean> => {
11→    return new Promise<boolean>(resolve => {
12→      resolveRef.current = resolve;
13→      setAlertState(options);
14→    });
15→  }, []);
16→
17→  const dismiss = useCallback((confirmed: boolean) => {
18→    if (resolveRef.current) {
19→      resolveRef.current(confirmed);
20→      resolveRef.current = null;
21→    }
22→    setAlertState(null);
23→  }, []);
24→
25→  return {
26→    alertState,
27→    confirmAlert,
28→    dismiss,
29→  };
